"""
christ layer: Joshua 12–14.
Ch 12 (24 v): Victory catalog — 31 conquered kings.
Ch 13 (33 v): Much land remains; Transjordanian allotments; Levi's inheritance.
Ch 14 (15 v): Caleb's wholehearted following; Hebron inheritance.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_comm(layer, book):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    return json.loads(p.read_text()) if p.exists() else {}

def save_comm(layer, book, data):
    p = ROOT / 'data' / 'commentary' / layer / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

CHRIST = {
  "12": {
    "1": "<p>A type: the victory catalog of all defeated kings. Chapter 12 is the book of Joshua's triumph-list — the systematic enumeration of every royal power brought low by YHWH through Israel. Paul&rsquo;s declaration that God &ldquo;disarmed the rulers and authorities and put them to open shame, triumphing over them in him [Christ]&rdquo; (Col 2:15) is the NT counterpart: the cross is the cosmic victory catalog where every spiritual power aligned against humanity is listed among the defeated. The catalog form itself is theologically significant — naming the defeated is the ancient victory-announcement that establishes the new king&rsquo;s universal dominion.</p>",
    "2": "<p>A type: Sihon king of the Amorites, who lived at Heshbon. Sihon and Og (v. 4) are the two prototypical anti-kingdom rulers defeated east of the Jordan — the conquest&rsquo;s first great victories (Num 21:21-35). The Psalms use these two defeats as paradigmatic examples of YHWH&rsquo;s warrior-power on behalf of his people (Ps 135:11; 136:19-20). Their defeat by Moses prefigures their listing here under Joshua — the conquest begun east of the Jordan is completed west of it, and Christ&rsquo;s work follows the same pattern: the defeat of the enemy is inaugurated at the cross and completed at the return.</p>",
    "3": "<p>A type: the geographic extent of Sihon&rsquo;s former domain — from the Arabah to the Sea of Kinnereth, from the Dead Sea to Beth-jeshimoth, southward to the slopes of Pisgah. The detail of the territorial boundaries signals that YHWH&rsquo;s victory is total: not merely the capital but the entire sovereign domain of the defeated king has passed to the new suzerain. In Ephesians 1:20-21, Christ is seated &ldquo;far above all rule and authority and power and dominion, and above every name that is named, not only in this age but also in the one to come&rdquo; — the cosmic extent of his kingship leaves no territory outside his domain.</p>",
    "4": "<p>A type: Og king of Bashan, who lived at Ashtaroth and Edrei, one of the remnant of the Rephaim. Og of Bashan is the giant-king — the last of the Rephaim (Deut 3:11: &ldquo;his bed was a bed of iron... nine cubits in length and four cubits in breadth&rdquo;). The defeat of the greatest Rephaim king by Moses under YHWH&rsquo;s command is a type of Christ&rsquo;s conquest of what seems invincible: the powers that appear too large and entrenched to defeat. Hebrews 2:14-15 describes Christ&rsquo;s incarnation as destroying &ldquo;the one who has the power of death, that is, the devil, and deliver all those who through fear of death were subject to lifelong slavery&rdquo; — the ultimate giant-king defeated.</p>",
    "5": "<p>A type: the geographic extent of Og&rsquo;s territory — half Gilead to the border of Sihon. The Bashan territory (high plateau northeast of the Jordan) became proverbially associated with power and fertility (Ps 22:12: &ldquo;strong bulls of Bashan have encircled me&rdquo;; Amos 4:1: &ldquo;cows of Bashan&rdquo; for the wealthy oppressors of Israel). Og&rsquo;s domain encompassed sixty cities (Deut 3:4-5) — a significant concentration of fortified strength. That even Og&rsquo;s extensive domain falls entirely under Moses&rsquo;s conquest anticipates the Pauline claim that Christ&rsquo;s dominion encompasses even the most entrenched and powerful spiritual territories.</p>",
    "6": "<p>A type: these two kingdoms Moses and YHWH&rsquo;s servant defeated, and Moses gave their land as a possession to the Reubenites, Gadites, and half the tribe of Manasseh. Moses defeated the eastern kingdoms but did not enter Canaan to complete the western conquest — Joshua completes what Moses began. This is the most explicit typological point the book of Joshua makes: Moses (the law) cannot complete the full inheritance; Joshua (whose name means YHWH saves) completes the work. Hebrews 4:8 makes the same point about Jesus: if Joshua had given them the true rest, God would not have spoken later of another day. The completion of Moses&rsquo;s work by Joshua is the type; the completion of the law&rsquo;s preparatory work by Christ is the antitype.</p>",
    "7": "<p>A type: the list of kings defeated by Joshua west of the Jordan, which the LORD God of Israel gave to the tribes of Israel as their possession. The transition from eastern to western victories marks the full scope of the conquest: both sides of the Jordan, both the Mosaic and Joshuanic campaigns, fall under YHWH&rsquo;s victory. The comprehensive formula &ldquo;which YHWH the God of Israel gave to the tribes of Israel as a possession&rdquo; frames every military victory as ultimately a divine gift — consistent with the holy-war theology throughout the book that YHWH is the true agent of victory. Christ&rsquo;s cosmic victory is similarly a gift he shares with his people: &ldquo;the meek shall inherit the earth&rdquo; (Matt 5:5) echoes the land-gift pattern.</p>",
    "8": "<p>A type: the catalog covers the hill country, lowland, Arabah, slopes, wilderness, and Negev — six distinct geographical zones covering the full geographic range of Canaan. The six-zone listing signals completeness of the conquest terrain, analogous to the listing of peoples (Hittites, Amorites, Canaanites, Perizzites, Hivites, Jebusites) representing the full human opposition. Colossians 1:16 describes the extent of Christ&rsquo;s creation-lordship and victory: &ldquo;all things were created through him and for him... whether thrones or dominions or rulers or authorities&rdquo; — the comprehensive catalog of spiritual powers corresponds to the comprehensive territorial catalog of Joshua 12.</p>",
    "9": "<p>A type: the king of Jericho. Jericho is the first city taken, the firstfruits of the conquest, whose walls fell without military assault through the divine march and trumpet-shout. The king of Jericho is the first name on the western victory roster. The firstfruits principle governing Jericho&rsquo;s total <em>cherem</em> looks forward to Christ as the firstfruits of resurrection (1 Cor 15:20-23): just as Jericho was the firstfruits of the land devoted entirely to YHWH, Christ&rsquo;s resurrection is the firstfruits of the general resurrection — the first and defining victory that guarantees all subsequent victories.</p>",
    "10": "<p>A type: the king of Jerusalem. Jerusalem (then Jebus) is conquered by Joshua but not permanently held until David (2 Sam 5:6-9). The king of Jerusalem is listed among the defeated — the city&rsquo;s future as David&rsquo;s capital, and ultimately as the city of Christ&rsquo;s death and resurrection, is contained in seed form in this single entry. The city that will become the center of the entire biblical redemptive story is already named as a conquered domain in Joshua&rsquo;s victory list. The new Jerusalem that descends from heaven in Revelation 21-22 is the eschatological fulfillment of the conquest claim first registered here.</p>",
    "11": "<p>A type: the king of Hebron. Hebron is Abraham&rsquo;s city — the site of the Cave of Machpelah where Abraham, Sarah, Isaac, Rebekah, Jacob, and Leah are buried (Gen 23; 49:29-32). The conquest of Hebron claimed the patriarchal burial ground and the land Abraham purchased as Israel&rsquo;s legal title to Canaan. Caleb will claim Hebron as his personal inheritance in chapter 14 — the most significant act of individual land-claiming in the book. David will be crowned king at Hebron (2 Sam 2:11) before taking Jerusalem. Hebron&rsquo;s listing here — king defeated, city claimable — is the typological foundation for all subsequent Hebronic events in Israel&rsquo;s covenant story.</p>",
    "12": "<p>A type: kings of Jarmuth and Lachish, members of the southern coalition (Josh 10:3). These two cities aligned with Jerusalem&rsquo;s king Adoni-zedek to resist Israel — the name Adoni-zedek (&ldquo;lord of righteousness/Zedek&rdquo;) echoes Melchizedek (&ldquo;king of righteousness/Zedek&rdquo;), Abraham&rsquo;s priestly benefactor. The contrast is deliberate in the narrative: where Melchizedek of Salem blessed Abraham (Gen 14:18-20), Adoni-zedek of Jerusalem opposed Joshua. Christ is the true Melchizedek-king (Heb 7:1-3: &ldquo;king of righteousness,&rdquo; king of peace), whose defeat of every Adoni-zedek figure establishes the true kingly-priestly order.</p>",
    "13": "<p>A type: kings of Eglon, Gezer. Eglon (city) shares its name with the Moabite king in Judges 3:12-30, whose assassination by Ehud begins the first Judges cycle of deliverance. The king of Gezer is listed here but Gezer itself will not be fully taken — it passes to Israel only when Pharaoh gives it as a dowry with his daughter in Solomon&rsquo;s time (1 Kings 9:16). The unfinished conquest of Gezer is one of the canonical examples of remaining Canaanite enclaves. Brief entries: each named king is a domain of opposition that Christ&rsquo;s cosmic victory encompasses, including the delayed and the partially-resolved.</p>",
    "14": "<p>A type: kings of Debir and Geder. Debir (also called Kiriath-sepher, &ldquo;city of the book/scribe&rdquo;) will become the prize that Caleb&rsquo;s nephew Othniel wins by conquering it, receiving Caleb&rsquo;s daughter Achsah as his wife (Josh 15:15-17; Judg 1:11-13). Othniel becomes the first judge of Israel. The king of Debir&rsquo;s defeat here makes possible the subsequent victory that will generate Israel&rsquo;s first deliverer — a layered typology where each conquest enables the next covenant act. The chain leads forward to Christ: each judge-deliverer in Israel&rsquo;s history points toward the ultimate Judge and Deliverer.</p>",
    "15": "<p>A type: kings of Hormah and Arad. Hormah (&ldquo;devoted to destruction&rdquo;) was the site of Israel&rsquo;s self-cursing vow in Numbers 21:2-3: &ldquo;If you will give this people into my hand, I will devote their cities to destruction.&rdquo; YHWH answered the vow and Israel devoted the Canaanites to destruction, naming the place Hormah. The listing of the king of Hormah here fulfills the covenant vow of Numbers 21, one of many narrative threads that Joshua&rsquo;s victory list closes. Christ is the one in whom every covenant vow finds its Yes (2 Cor 1:20) — the pattern of promised destruction of the enemies of God&rsquo;s people is fulfilled in him.</p>",
    "16": "<p>A type: kings of Libnah and Adullam. Adullam is the location of David&rsquo;s cave-headquarters during his flight from Saul (1 Sam 22:1) — the future site of the anointed king in exile becomes one of the 31 conquered domains. Every site that will figure in Israel&rsquo;s covenant history — including the hiding places of the rejected-and-vindicated king — is already claimed in the conquest. The pattern of the anointed one who passes through a period of rejection and hiding before enthronement is the pattern of David and ultimately of Christ, whose death and descent precede his resurrection and exaltation.</p>",
    "17": "<p>A type: kings of Tappuah and Hepher. Brief entries in the victory catalog. These smaller city-kingdoms represent the comprehensive scope of the conquest — not merely the major cities but the minor administrative centers scattered through the hill country and lowlands. The thoroughness of the list reflects the thoroughness of the divine gift: the entire land in all its administrative complexity belongs to YHWH and is redistributed to his people. Revelation 11:15 — &ldquo;The kingdom of the world has become the kingdom of our Lord and of his Christ&rdquo; — is the eschatological fulfillment of the comprehensive conquest register.</p>",
    "18": "<p>A type: kings of Aphek and Lasharon. Aphek recurs in Israel&rsquo;s history as a site of Philistine military operations — it is at Aphek that the Philistines encamp before the battle where the ark is captured (1 Sam 4:1). The king of Aphek is listed among Joshua&rsquo;s defeated, but Aphek will require further battles in subsequent generations. This is the pattern of the &ldquo;already and not yet&rdquo; in Israel&rsquo;s conquest: the victory is established in principle and listed in the catalog, but experiential possession of individual sites requires ongoing faithfulness and engagement.</p>",
    "19": "<p>A type: kings of Madon and Hazor. Hazor is the great northern city-state — &ldquo;formerly the head of all those kingdoms&rdquo; (Josh 11:10) — whose king Jabin led the northern coalition against Israel. Joshua burned Hazor completely. But a second king Jabin of Hazor will oppress Israel in Judges 4, requiring Deborah&rsquo;s deliverance. The listing of Hazor&rsquo;s defeated king here, while the city will require reconquest in the Judges period, illustrates the recurring-conquest pattern: the complete victory of the Christ-figure does not eliminate the need for subsequent spiritual warfare in each generation, though the ultimate outcome remains settled.</p>",
    "20": "<p>A type: kings of Shimron-meron and Achshaph. These northern cities were part of the Hazor coalition (Josh 11:1). The northern coalition&rsquo;s defeat made possible the settlement of Galilee — the region where Jesus conducted the majority of his ministry (Matt 4:15-16: &ldquo;Galilee of the Gentiles — the people dwelling in darkness have seen a great light&rdquo;). The conquest of these cities created the space in which the Light of the world would eventually walk. The geography of Joshua&rsquo;s victory is the geography of Christ&rsquo;s ministry.</p>",
    "21": "<p>A type: kings of Taanach and Megiddo. Megiddo is the most prophetically significant site in this list. &ldquo;Armageddon&rdquo; in Revelation 16:16 is a Greek transliteration of <em>Har Megiddo</em> (Mountain/Hill of Megiddo) — the gathering place of the kings of the earth for the final battle against the returning Christ. The listing of the king of Megiddo among Joshua&rsquo;s defeated anticipates the final &ldquo;Megiddo&rdquo; in Revelation 19:19-21, where the beast and the kings of the earth are gathered against the rider on the white horse and are defeated. Joshua&rsquo;s conquest of Megiddo is the typological first entry in a long chain culminating in the eschatological victory.</p>",
    "22": "<p>A type: kings of Kedesh and Jokneam. Kedesh is one of the six cities of refuge (Josh 20:7) — a city of asylum where one who killed unintentionally could flee from the avenger of blood. The city that provides refuge for the manslayer is among the conquered cities whose king is listed in the defeat catalog. This juxtaposition is theologically rich: the city of refuge (type of Christ as our refuge, our shelter from the consequences of sin) is established in a domain already conquered by the divine warrior. Christ as our city of refuge (Heb 6:18: &ldquo;we who have fled for refuge might have strong encouragement to hold fast to the hope set before us&rdquo;) inhabits a domain whose victory was established before we fled to it.</p>",
    "23": "<p>A type: king of Dor on the coast and king of Goyim in Gilgal. &ldquo;Goyim&rdquo; (nations/Gentiles) is a notable name — a king whose domain is named after the nations. The conquest of the king of Goyim in a land where Gentile peoples have sovereignty is the type of Christ&rsquo;s universal kingship over all nations: &ldquo;Ask of me, and I will make the nations (<em>goyim</em>) your heritage, and the ends of the earth your possession&rdquo; (Ps 2:8). The victory over the king of Goyim in Joshua&rsquo;s day anticipates the Great Commission and Christ&rsquo;s kingship over all <em>goyim</em>.</p>",
    "24": "<p>A type: thirty-one kings in all. The total — thirty-one kings, thirty-one domains of royal power brought under YHWH&rsquo;s suzerainty through Joshua — is the victory register of the entire Canaanite campaign. The number thirty-one is not symbolic (unlike the seven-nation lists) but simply comprehensive: however many kings held sovereignty in Canaan, all are defeated and listed. The NT counterpart is Ephesians 1:21 — Christ is exalted &ldquo;far above all rule and authority and power and dominion, and above every name that is named&rdquo; — and Philippians 2:10-11: &ldquo;at the name of Jesus every knee should bow, in heaven and on earth and under the earth, and every tongue confess that Jesus Christ is Lord.&rdquo; The victory catalog of Joshua 12 is the shadow of the cosmic catalog of Christ&rsquo;s universal lordship.</p>"
  },
  "13": {
    "1": "<p>A direct revelation: &ldquo;You are old and advanced in years, and there remains yet very much land to possess.&rdquo; YHWH&rsquo;s word to the aging Joshua that the conquest is incomplete is the central theological tension that Hebrews unpacks. Hebrews 4:8: &ldquo;For if Joshua had given them rest, God would not have spoken of another day later on&rdquo; (citing Ps 95:11). The &ldquo;much land that remains&rdquo; is not a failure of the conquest but an embedded pointer: the Canaan-rest is real but provisional, a sign of a greater rest still to come. Christ is the Joshua who will give what the original Joshua could not — the final, unending, perfect rest of God&rsquo;s dwelling with his people (Rev 21:3-4).</p>",
    "2": "<p>A type: the land that remains — the territory of the Philistines and the Geshurites. The Philistines represent the perennial enemy that Israel&rsquo;s judges and kings will combat for the entire period of the monarchy — the threat that cannot be resolved by the initial conquest. David will definitively defeat the Philistines (2 Sam 5:17-25; 8:1), but only after Israel has suffered centuries of Philistine oppression. The progressive conquest of remaining enemies across Israel&rsquo;s history is the pattern of the Christian life: the decisive victory is won at the cross, but experiential possession of that victory is a progressive, lifelong reality (Phil 3:12-14: &ldquo;not that I have already obtained this or am already perfect, but I press on&rdquo;).</p>",
    "3": "<p>A type: the Canaanite territory from the Shihor to Ekron and the five lords of the Philistines (Gaza, Ashdod, Ashkelon, Gath, Ekron). The five Philistine city-states — the pentapolis — will become the symbolic enemy of Israel&rsquo;s full covenantal possession from Judges through 1 Samuel. Goliath from Gath is the Philistine champion who will one day be defeated by the shepherd-king David (1 Sam 17). The fact that these domains are &ldquo;considered Canaanite&rdquo; places the Philistine presence within the larger framework of the as-yet-unconquered territory — the remaining work that points to the greater Joshua who will complete it.</p>",
    "4": "<p>A type: the land of the Canaanites and Mearah belonging to the Sidonians, to Aphek, to the boundary of the Amorites. Sidon is the great Phoenician city-state that will recur throughout Israel&rsquo;s history, and whose territory Jesus will visit (Mark 7:24-31: the Syrophoenician woman at Tyre and Sidon). Jesus&rsquo;s deliberate journeys into Gentile territories — Tyre, Sidon, the Decapolis — are the NT counterpart of the remaining-territory vision: the domains that the Canaanite conquest did not reach, Christ reaches personally and extends the covenant blessing.</p>",
    "5": "<p>A type: Gebel (Byblos) and all Lebanon to the east, to Lebo-hamath. Lebanon&rsquo;s cedar forests were used by Solomon for the temple (1 Kings 5:6-10) — the remaining northern territory beyond Israel&rsquo;s direct conquest becomes the source of materials for YHWH&rsquo;s dwelling place. The territory that could not be conquered militarily is incorporated by trade and covenant into the temple project. The eschatological gathering of the nations&rsquo; wealth into the new Jerusalem (Isa 60:13: &ldquo;the glory of Lebanon shall come to you&rdquo;; Rev 21:24: &ldquo;the kings of the earth will bring their glory into it&rdquo;) is the ultimate incorporation of the remaining territories.</p>",
    "6": "<p>A direct revelation: &ldquo;I myself will drive them out from before the people of Israel; only allot the land to Israel for an inheritance as I have commanded you.&rdquo; YHWH&rsquo;s promise to complete the driving-out himself — even the remaining territories — is the basis for the inheritance distribution that follows. Philippians 1:6: &ldquo;I am sure of this, that he who began a good work in you will bring it to completion at the day of Jesus Christ.&rdquo; The divine first-person commitment to complete what was begun is the ground of the inheritance-distribution: Joshua can allot the land as if the remaining enemies are already expelled because YHWH has pledged to do it. The believer can live in the full inheritance of Christ because the one who began the work pledges to complete it.</p>",
    "7": "<p>A type: &ldquo;Now therefore divide this land for an inheritance to the nine tribes and the half-tribe of Manasseh.&rdquo; The inheritance distribution — land allocated as gift, not earned by settlement — is the enacted form of the covenant promise. Ephesians 1:11: &ldquo;In him we have obtained an inheritance, having been predestined according to the purpose of him who works all things according to the counsel of his will.&rdquo; The land-lot process (the <em>goral</em>) that determines each tribe&rsquo;s portion mirrors the election concept: the inheritance is determined by divine assignment, not human achievement or preference.</p>",
    "8": "<p>A type: the Reubenites and Gadites received their inheritance across the Jordan with Moses, as YHWH&rsquo;s servant had given it to them. The Transjordanian tribes received their inheritance before crossing — they were given the promise and the land before entering Canaan proper. This anticipates the realized-eschatology dimension of the NT: believers are &ldquo;blessed with every spiritual blessing in the heavenly places&rdquo; (Eph 1:3) now, before the final inheritance is physically possessed. The possession is complete in the divine declaration before it is experientially inhabited.</p>",
    "9": "<p>A type: the territory from Aroer on the Arnon to Medeba includes the plateau of Moab. The Transjordanian territory is defined precisely — from the boundary of Moab, through the plateau cities, to the border of the Ammonites. This precision in describing territory that Israel will hold signifies that every inch of the covenant land is accounted for by the divine land-lord. Hebrews 11:16 speaks of the patriarchs as desiring &ldquo;a better country, that is, a heavenly one,&rdquo; and the precise enumeration of earthly territory points to the specificity of the heavenly inheritance — God&rsquo;s gifts are not vague but precisely given to precisely named recipients.</p>",
    "10": "<p>A type: all the cities of Sihon king of the Amorites as far as the boundary of the Ammonites. The towns of the former Sihon-kingdom are now Reuben&rsquo;s and Gad&rsquo;s inheritance — the anti-kingdom&rsquo;s domain becomes the covenant people&rsquo;s home. 2 Corinthians 10:4-5: &ldquo;The weapons of our warfare are not of the flesh but have divine power to destroy strongholds... take every thought captive to obey Christ.&rdquo; The strongholds of Sihon become Israel&rsquo;s towns — the strongholds of the enemy become the territory of Christ&rsquo;s people.</p>",
    "11": "<p>A type: Gilead and the territory of the Geshurites and Maacathites and all Mount Hermon and all Bashan to Salecah. The Bashan territory — Og&rsquo;s former kingdom — now belongs to the half-tribe of Manasseh. Mount Hermon, the highest point in the region, was the location of Jesus&rsquo;s transfiguration (Matt 17:1-8; the Hermon-transfiguration identification is widely accepted). The mountain of the defeated giant-king Og became the mountain of the glorious divine Son — the geography of conquest transformed into the geography of revelation.</p>",
    "12": "<p>A type: all the kingdom of Og in Bashan — the remnant of the Rephaim, whom Moses defeated. The repeated mention of Og as the last of the Rephaim (cf. 12:4; Deut 3:11) establishes that the conquest of Canaan eliminated the line of the nephilim/Rephaim giants. In the NT, the Rephaim/nephilim tradition (Gen 6:1-4; Num 13:33) underlies the language of spiritual powers: the &ldquo;giants&rdquo; of the spiritual realm are the rulers and authorities Paul describes in Ephesians 6:12. Christ&rsquo;s defeat of the last Rephaim&rsquo;s descendants — the cosmic powers aligned against humanity — is the fulfillment of the defeat-of-Og type.</p>",
    "13": "<p>A type: the Israelites did not drive out the Geshurites or the Maacathites; Geshur and Maacath live in the midst of Israel to this day. This is the paradigmatic failed-conquest notice: despite the allotment, the actual expulsion was incomplete. The Geshurites will appear again when Absalom flees to Geshur (his mother&rsquo;s homeland, 2 Sam 3:3) after killing Amnon — the unconquered territory becomes the refuge of David&rsquo;s most dangerous son. The remaining Canaanites who corrupt Israel&rsquo;s covenant life are the type of the &ldquo;sin that so easily entangles&rdquo; (Heb 12:1) that believers must actively resist even in the realized inheritance.</p>",
    "14": "<p>A direct revelation: &ldquo;To the tribe of Levi alone Moses gave no inheritance; the offerings by fire to YHWH, the God of Israel, are their inheritance, as he said to them.&rdquo; The Levitical inheritance is YHWH himself — his offerings, his service, his presence. This principle has two NT fulfillments: (1) Christ as our inheritance — &ldquo;YHWH is my portion&rdquo; (Lam 3:24; Ps 73:26) becomes the believer&rsquo;s reality in Christ, who gives himself as the inheritance of all his people; (2) the church as a royal priesthood (1 Pet 2:9) has no earthly territorial inheritance but is given God himself. Revelation 21:3: &ldquo;God himself will be with them as their God&rdquo; — the Levitical pattern of divine-presence-as-inheritance is universalized to all God&rsquo;s people in the new creation.</p>",
    "15": "<p>A type: the allotment to the tribe of Reuben — the firstborn who forfeited the double inheritance (Gen 49:3-4: &ldquo;Reuben... unstable as water, you shall not have preeminence&rdquo;). Reuben receives a portion — not disinherited, but not the preeminent inheritance he might have had. Jacob&rsquo;s prophetic word at his deathbed (Gen 49:3-4) is here enacted: the firstborn receives a territory, but Judah will hold the preeminence (Gen 49:10: &ldquo;the scepter shall not depart from Judah&rdquo;). The pattern of the firstborn giving way to the chosen son is the recurring pattern that reaches its fulfillment in Christ, the elect one through whom all the tribes receive their inheritance.</p>",
    "16": "<p>A type: the specific cities of Reuben&rsquo;s allotment — Aroer, Dibon, Bamoth-baal, Beth-baal-meon. The inclusion of &ldquo;Baal&rdquo; in city names (Beth-baal-meon = &ldquo;house of the lord of the dwelling&rdquo;) in Reuben&rsquo;s territory signals the ongoing Baal-worship pressure that will corrupt the Transjordanian tribes in the Judges period (and Reuben will largely disappear from Israel&rsquo;s tribal life). The danger of inheriting cities named after Baal is the danger of habitation shaping worship — the pull of the place&rsquo;s identity on its inhabitants. Christ&rsquo;s overcoming of Baal-worship (Elijah&rsquo;s Carmel victory, 1 Kings 18) is the prophetic preview of the complete displacement of every competing name by the name of Jesus (Phil 2:10).</p>",
    "17": "<p>A type: Heshbon and its cities on the plateau — Dibon, Bamoth-baal, Beth-baal-meon. Heshbon was Sihon&rsquo;s capital, the center of Amorite power east of the Jordan. The fact that former Sihon-cities become Reubenite inheritance demonstrates the complete transfer of sovereignty: the anti-kingdom&rsquo;s administrative center becomes the covenant people&rsquo;s home. The NT pattern is 2 Corinthians 10:5: &ldquo;we destroy arguments and every lofty opinion raised against the knowledge of God, and take every thought captive to obey Christ&rdquo; — the strongholds of the enemy become the domain of Christ&rsquo;s obedience.</p>",
    "18": "<p>A type: Jahaz, Kedemoth, Mephaath — additional Reubenite cities. These were the sites of Moses&rsquo;s abortive peace-mission to Sihon (Deut 2:26-29: Moses sent messengers from &ldquo;the wilderness of Kedemoth&rdquo; asking permission to pass peacefully). Sihon refused, fought, and was defeated. The city from which the peace-offer was sent becomes part of the inheritance of those who prevailed. The principle: when God&rsquo;s offer of peace is rejected, judgment falls; and the very ground from which the offer was made becomes the inheritance of those who were faithful. Christ&rsquo;s offer of peace to Jerusalem (Matt 23:37-39) follows the same pattern — rejection followed by judgment, and the inheritance passing to those who receive him.</p>",
    "19": "<p>A type: Kiriathaim, Sibmah, and Zereth-shahar on the hill of the valley. Sibmah will appear in the prophets as a vineyard associated with mourning and judgment (Isa 16:8-9; Jer 48:32: &ldquo;I will weep for you as Jazer weeps, O vine of Sibmah&rdquo;) when Moab devastates it. The territory given to Reuben as inheritance will eventually pass through Moabite destruction — the Reubenite failure to hold the inheritance is the type of the apostate who does not maintain possession of their allotted inheritance. Hebrews 3-4 uses the wilderness generation&rsquo;s failure to enter Canaan-rest as the paradigm warning against failing to maintain covenant faithfulness.</p>",
    "20": "<p>A type: Beth-peor, the slopes of Pisgah, Beth-jeshimoth — Reubenite cities. Beth-peor is the most fraught site on this list: it is where Israel committed sexual immorality with Moabite women and worshiped Baal of Peor (Num 25:1-9), resulting in a plague that killed 24,000. Moses is buried &ldquo;in the valley opposite Beth-peor&rdquo; (Deut 34:6). Reuben&rsquo;s inheritance includes the site of Israel&rsquo;s most catastrophic sexual-idolatry sin — a perpetual warning within the geography of the allotment. Christ&rsquo;s intercessory high priesthood (Heb 7:25) is the antitype of Phinehas&rsquo;s atonement act at Peor (Num 25:7-13): the priest who &ldquo;always lives to make intercession&rdquo; permanently resolves what Peor only temporarily checked.</p>",
    "21": "<p>A type: all the cities of the plateau and the whole kingdom of Sihon, including the five princes of Midian — Evi, Rekem, Zur, Hur, and Reba. The five Midianite princes killed alongside Sihon at this campaign are also killed in the later Midianite war of Numbers 31:8. Balaam son of Beor is explicitly noted as killed (v. 22). The defeat of the Midianite princes who aligned with Sihon connects the Transjordanian conquest to the Balaam episode of Numbers 22-24: the entire network of opposition to Israel — Moabite king, Midianite princes, professional diviner — is brought under the same defeat. Christ&rsquo;s triumph encompasses every form of spiritual opposition: political, cultic, and occultic.</p>",
    "22": "<p>A type: Balaam son of Beor, the diviner, was killed with the sword by the people of Israel among the rest of their slain. Balaam, whose mouth YHWH controlled to bless Israel instead of cursing (Num 22-24), nonetheless counseled Moab to corrupt Israel through Baal-Peor (Num 31:16; Rev 2:14: &ldquo;you have some there who hold the teaching of Balaam&rdquo;). The one who could not curse Israel directly corrupted them through sexual-idolatry bait — and is ultimately killed in the Midianite war. 2 Peter 2:15-16 names &ldquo;the way of Balaam&rdquo; as the path of the false prophet who loves gain from wrongdoing. The death of Balaam is the type of the definitive end of the false-prophet spirit, fully overcome in Christ who is the faithful True Witness (Rev 3:14).</p>",
    "23": "<p>A type: the Jordan boundary of the Reubenite inheritance, their cities and villages. The Jordan as boundary is also a baptismal type throughout Joshua — the river that must be crossed to enter the inheritance. Reuben&rsquo;s territory is on the far side of the Jordan from the main inheritance of Israel; they have an inheritance, but separated by the river from the central sanctuary&rsquo;s access. This spatial separation will eventually contribute to the altar-controversy of Joshua 22, where the Transjordanian tribes build a witness-altar because they fear future generations will be denied access to YHWH&rsquo;s covenant. The anxiety about separation from the covenant presence is answered in Christ: Romans 8:38-39 declares that nothing can separate believers from the love of God in Christ Jesus.</p>",
    "24": "<p>A type: the allotment to the tribe of Gad — the tribe whose name means &ldquo;fortune/luck&rdquo; (Gen 30:11, Leah: &ldquo;a troop comes!&rdquo;). Gad&rsquo;s fighters are described in 1 Chronicles 12:8 as &ldquo;mighty and experienced warriors, expert with shield and spear, whose faces were like the faces of lions, and who were swift as gazelles on the mountains&rdquo; — they join David at Ziklag. The warrior character of Gad fits the Transjordanian territory that requires ongoing vigilance against Ammonite and Moabite pressure. Christ as the Lion of the tribe of Judah (Rev 5:5) is the ultimate warrior-king to whom all tribal warrior traditions point.</p>",
    "25": "<p>A type: Gad&rsquo;s territory included Jazer, all the cities of Gilead, half the land of the Ammonites to Aroer near Rabbah. Rabbah is the Ammonite capital — the later site of Uriah the Hittite&rsquo;s death engineered by David (2 Sam 11:14-17), and the city that David will besiege and capture (2 Sam 12:26-31). David&rsquo;s Rabbah campaign is one of the ethical low points of his reign and one of the narrative high points of the cost of sin in Israel&rsquo;s covenant life. The territory around Rabbah, allotted to Gad, becomes the backdrop for the David-Bathsheba-Uriah tragedy — the conquest territory that should have been peacefully settled becomes the site of covenant violation.</p>",
    "26": "<p>A type: from Heshbon to Ramath-mizpah and Betonim, from Mahanaim to the boundary of Debir. Mahanaim is where Jacob encountered &ldquo;the camp of God&rdquo; (<em>machane Elohim</em>) and named the place Mahanaim (&ldquo;two camps,&rdquo; Gen 32:2). It becomes the capital of Ish-bosheth&rsquo;s rival kingdom (2 Sam 2:8) and David&rsquo;s refuge during Absalom&rsquo;s rebellion (2 Sam 17:24). The site of Jacob&rsquo;s angelic encounter, located in Gad&rsquo;s allotment, carries the patriarchal promise through the covenant history: from Jacob&rsquo;s night wrestling to David&rsquo;s exile to the final angelic camp around God&rsquo;s people (Rev 7:9-12).</p>",
    "27": "<p>A type: in the valley — Beth-haram, Beth-nimrah, Succoth, Zaphon — the rest of the kingdom of Sihon, with the Jordan as its eastern boundary to the tip of the Sea of Kinnereth. Succoth is Jacob&rsquo;s first stop after his reconciliation with Esau (Gen 33:17: &ldquo;Jacob journeyed to Succoth, built himself a house, and made booths for his livestock; therefore the place is called Succoth&rdquo;). The patriarchal waystation becomes part of Gad&rsquo;s territorial inheritance. The Feast of Booths (<em>Sukkot</em>) — the feast of temporary dwellings that commemorates the wilderness period — finds its NT fulfillment in John 7:37-39 (Jesus&rsquo;s declaration on the last day of Sukkot: &ldquo;if anyone thirsts, let him come to me and drink&rdquo;) and Rev 21:3 (God&rsquo;s tabernacle is with men).</p>",
    "28": "<p>A type: the inheritance of Gad, their cities and villages. The formulaic close of each tribal allotment — &ldquo;their cities and villages&rdquo; — signals the completed gift-transfer. The inheritance is both the named land and the settled life within it: cities (political-administrative reality) and villages (agricultural-communal reality). The NT inheritance is similarly both cosmic (&ldquo;heirs of God and fellow heirs with Christ,&rdquo; Rom 8:17) and concrete (&ldquo;the meek shall inherit the earth,&rdquo; Matt 5:5; &ldquo;the new Jerusalem,&rdquo; Rev 21-22). The OT formula of inheritance-completion anticipates the NT promise&rsquo;s specificity and completeness.</p>",
    "29": "<p>A type: the half-tribe of Manasseh&rsquo;s Transjordanian allotment. Manasseh is Joseph&rsquo;s firstborn son whose birth and blessing were marked by extraordinary divine reversal (Gen 48:13-20: Jacob deliberately crossed his hands to give Ephraim the greater blessing over Manasseh). The half-tribe across the Jordan becomes part of the Israelite identity — separated from the main tribal territory yet still fully within the covenant inheritance. The pattern of divided inheritance (half in Transjordan, half in Canaan) mirrors the &ldquo;already/not yet&rdquo; structure of the believer&rsquo;s inheritance: possessing in part while awaiting full possession.</p>",
    "30": "<p>A type: the Manassite territory included Mahanaim, all Bashan — the entire kingdom of Og — and the sixty cities of Jair in Bashan. The &ldquo;tent-villages of Jair&rdquo; (<em>chavvot Ya'ir</em>) are the sixty Beshanian cities claimed by the Manassite hero Jair (Num 32:41; Deut 3:14). The number sixty is the same as the sixty queens and eighty concubines of Song of Solomon 6:8 — a number denoting abundance. The sixty-city allotment of Manasseh&rsquo;s half-tribe in Og&rsquo;s former domain is the largest single concentrated inheritance in the Transjordanian division, signaling that Manasseh&rsquo;s share in the defeated giant-king&rsquo;s territory is comprehensive.</p>",
    "31": "<p>A type: half of Gilead, Ashtaroth, and Edrei — the royal cities of Og in Bashan — for half the sons of Machir son of Manasseh. Machir is the firstborn of Manasseh (Num 26:29) and the most specifically military of the Manassite clans — &ldquo;a man of war&rdquo; (Num 32:39-41). The inheritance of Og&rsquo;s royal cities — the capital of the giant-king — going specifically to the warrior-clan of Machir enacts the principle that the most formidable inheritances require the most committed faithfulness. In the NT, the &ldquo;well done, good and faithful servant&rdquo; (Matt 25:21) leads to authority over &ldquo;many things&rdquo; — the inheritance proportioned to faithfulness in warfare against the enemy.</p>",
    "32": "<p>A type: these are the territories Moses distributed in the plains of Moab, across the Jordan east of Jericho. The formulaic close of the Transjordanian distribution connects it to Moses&rsquo;s Mosaic authority — these inheritances have the same divine legitimacy as the western ones. The plains of Moab (in Moabite territory by definition, yet now the distribution-ground of Israel&rsquo;s inheritance) signal that the covenant&rsquo;s claim extends beyond Israel&rsquo;s conventional boundaries: God distributes inheritance from unexpected ground. Christ&rsquo;s mission extends beyond expected religious boundaries in the same pattern — distributing covenant inheritance from Gentile soil.</p>",
    "33": "<p>A direct revelation: &ldquo;But to the tribe of Levi Moses gave no inheritance; YHWH, the God of Israel, is their inheritance, as he said to them.&rdquo; The chapter closes with the Levitical formula of divine-presence-as-inheritance. This is the theological peak of chapter 13: in a chapter entirely about land distribution, the closing word is that one tribe receives not land but God himself. First Peter 2:9: &ldquo;But you are a chosen race, a royal priesthood, a holy nation, a people for his own possession.&rdquo; The NT church, as a royal priesthood, takes on the Levitical pattern: their inheritance is not earthly territory but the divine presence itself. Revelation 21:22: &ldquo;I saw no temple in the city, for its temple is the Lord God the Almighty and the Lamb&rdquo; — the Levitical temple-as-inheritance is fulfilled in the Lamb as the temple.</p>"
  },
  "14": {
    "1": "<p>A type: the inheritance of the western tribes was allotted by Eleazar the priest and Joshua and the heads of the fathers&rsquo; houses. The distribution of the western inheritance involves both the military leader (Joshua) and the high priest (Eleazar) — the dual authority of king and priest that governs covenant life. Hebrews 7:1-3 identifies Christ as both king and priest after the order of Melchizedek — the one who holds both offices simultaneously, permanently. Joshua and Eleazar are the separated types whose unity finds its fulfillment in the single person of Christ who &ldquo;always lives to make intercession&rdquo; (Heb 7:25) and simultaneously rules as king on David&rsquo;s throne.</p>",
    "2": "<p>A type: their inheritance was assigned by lot, as YHWH commanded through Moses for the nine and a half tribes. The lot (<em>goral</em>) as the mechanism of inheritance-assignment is a form of divine oracle — human randomness as the instrument of divine determination. Proverbs 16:33: &ldquo;The lot is cast into the lap, but its every decision is from the LORD.&rdquo; The lot-determined inheritance is the OT picture of election: the recipient does not choose their portion; the divine lot-caster determines it. Ephesians 1:11: &ldquo;In him we have obtained an inheritance, having been predestined according to the purpose of him who works all things according to the counsel of his will.&rdquo; The lot-inheritance of the tribes is the type of the predestined inheritance of the church.</p>",
    "3": "<p>A type: Moses had already given the inheritance of the two and a half tribes across the Jordan. The reminder that part of the inheritance preceded the western distribution reinforces the completeness of the divine gift across both sides of the Jordan. The &ldquo;already given&rdquo; aspect of the Transjordanian inheritance is the type of the &ldquo;already&rdquo; in the NT eschatological scheme: Ephesians 2:6: &ldquo;he raised us up with him and seated us with him in the heavenly places in Christ Jesus&rdquo; — the inheritance is already granted in Christ even while the full experiential possession awaits the resurrection.</p>",
    "4": "<p>A type: the sons of Joseph constituted two tribes (Manasseh and Ephraim), and the Levites received no portion but only cities and pasturelands. Joseph&rsquo;s double-portion through his two sons (Manasseh and Ephraim) is the enacted form of Jacob&rsquo;s blessing to Joseph: &ldquo;I am giving you one portion more than your brothers, which I took from the hand of the Amorites with my sword and with my bow&rdquo; (Gen 48:22). The double portion of the beloved son prefigures Christ as the one who inherits all things (Heb 1:2: &ldquo;his Son, whom he appointed the heir of all things&rdquo;) and shares his full inheritance with his co-heirs (Rom 8:17).</p>",
    "5": "<p>A type: as YHWH commanded Moses, so the people of Israel did and divided the land. The explicit compliance formula — &ldquo;as YHWH commanded... so they did&rdquo; — frames the entire inheritance-distribution as an act of covenant obedience, not merely political-administrative necessity. The distribution is worship as much as governance: enacting YHWH&rsquo;s word is the form of their covenant faithfulness. Christ&rsquo;s own obedience as the ground of our inheritance (Phil 2:8: &ldquo;obedient to the point of death&rdquo;; Heb 5:8: &ldquo;learned obedience through what he suffered&rdquo;) is the fulfillment of the obedience-grounded distribution pattern.</p>",
    "6": "<p>A type: Caleb son of Jephunneh the Kenizzite came to Joshua and recalled Moses&rsquo;s promise: &ldquo;you know what YHWH said to Moses the man of God about you and me at Kadesh-barnea.&rdquo; Caleb is a Kenizzite — a non-Israelite clan incorporated into Judah (Gen 15:19 names the Kenizzites among the Canaanite peoples). The foreigner who enters Israel by faith and receives an inheritance because of wholehearted covenant faithfulness is the type of the Gentile believer grafted into Israel&rsquo;s covenant through faith (Rom 11:17-18: &ldquo;a wild olive shoot... grafted in among the others and now share in the nourishing root of the olive tree&rdquo;). Caleb&rsquo;s inheritance is not despite his foreign origin but through his wholehearted following of YHWH.</p>",
    "7": "<p>A type: Caleb was forty years old when Moses sent him from Kadesh-barnea to spy the land, and he brought back an honest report while his colleagues frightened the people. The honest report from the faithful minority against the fearful majority is the prophetic pattern: the two faithful spies (Caleb and Joshua) are the minority who believe the divine promise while the majority calculate by human strength. Christ&rsquo;s &ldquo;Do not be afraid&rdquo; (John 14:27: &ldquo;Peace I leave with you; my peace I give to you. Not as the world gives do I give to you. Let not your hearts be troubled&rdquo;) is the NT form of the faithful spy&rsquo;s report: the land can be taken because YHWH is the true warrior.</p>",
    "8": "<p>A direct revelation (via Joshua&rsquo;s words): &ldquo;But I wholly followed YHWH my God (<em>milei acharei YHWH Elohai</em>).&rdquo; The phrase <em>milei acharei</em> (&ldquo;fully after,&rdquo; &ldquo;wholeheartedly following&rdquo;) is Caleb&rsquo;s defining characteristic — used six times in the Caleb passages (Num 14:24; 32:12; Deut 1:36; Josh 14:8, 9, 14). It denotes unreserved, total attachment and following. Revelation 14:4: &ldquo;It is these who follow the Lamb wherever he goes&rdquo; — the 144,000 are characterized by the exact same quality as Caleb&rsquo;s wholehearted following. The <em>milei acharei</em> saints of every era form the Caleb-pattern: undivided devotion that perseveres through long years of delayed inheritance.</p>",
    "9": "<p>A direct revelation (promised to Caleb via Moses): &ldquo;The land on which your foot has trodden shall be an inheritance for you and your children forever, because you have wholly followed YHWH my God.&rdquo; The promise-retelling is 45 years old: Moses spoke this word at Kadesh-barnea, and Caleb has waited the entire wilderness period and the seven-year conquest to claim it. The patient expectation of a promised inheritance is the pattern of the believer&rsquo;s hope: &ldquo;through faith and patience [believers] inherit the promises&rdquo; (Heb 6:12). Caleb&rsquo;s 45-year wait for the promised hill country is the type of the church&rsquo;s patient expectation of the promised inheritance.</p>",
    "10": "<p>A type: &ldquo;And now behold, YHWH has kept me alive, just as he said, these forty-five years since the time that YHWH spoke this word to Moses, while Israel walked in the wilderness; and now, behold, I am this day eighty-five years old.&rdquo; Caleb&rsquo;s testimony — YHWH kept me alive as he said — is the lived-out form of divine promise-keeping. At 85, still claiming the difficult promise, Caleb embodies the perseverance that does not shrink from the inheritance just because it requires continued engagement with the enemy. First Peter 1:3-5: &ldquo;an inheritance that is imperishable, undefiled, and unfading, kept in heaven for you, who by God&rsquo;s power are being guarded through faith for a salvation ready to be revealed in the last time&rdquo; — kept by God for us, as God kept Caleb for his inheritance.</p>",
    "11": "<p>A type: &ldquo;I am still as strong today as I was in the day that Moses sent me; my strength now is as my strength was then, for war and for going and coming.&rdquo; Caleb&rsquo;s declaration of undiminished strength at 85 — for both war and travel — is not mere biological boasting but a covenant testimony: YHWH has maintained him in the strength needed for the inheritance. Isaiah 40:31: &ldquo;those who wait for YHWH shall renew their strength; they shall mount up with wings like eagles; they shall run and not be weary; they shall walk and not faint.&rdquo; Caleb&rsquo;s preserved strength is the embodied illustration of the Isaianic promise about those who wait on YHWH — the patient faith of 45 years maintained by divine strength.</p>",
    "12": "<p>A type: &ldquo;Now give me this hill country of which YHWH spoke on that day... Perhaps YHWH will be with me, and I shall drive them out as YHWH said.&rdquo; Caleb&rsquo;s request for the Anakim-occupied hill country — the most difficult territory, inhabited by the giants who caused the spies to feel like grasshoppers (Num 13:33) — is faith claiming the hardest promise. At 85, he asks for the portion that requires the most warfare. Matthew 17:20: &ldquo;If you have faith like a grain of mustard seed, you will say to this mountain, &lsquo;Move from here to there,&rsquo; and it will move&rdquo; — the faith that claims the giant-inhabited hill country at 85 is the same kind of faith Jesus describes as mountain-moving: not the absence of giants but the presence of YHWH.</p>",
    "13": "<p>A type: Joshua blessed him and gave Hebron to Caleb son of Jephunneh for an inheritance. The blessing Joshua gives before conferring the inheritance parallels the priestly blessing that accompanies each covenant gift. Hebrews 7:7: &ldquo;it is beyond dispute that the inferior is blessed by the superior&rdquo; — here Joshua, as YHWH&rsquo;s appointed covenant-leader, blesses Caleb as the act of inheritance-conferral. The ultimate blessing is the one pronounced by Christ upon his own: &ldquo;Come, you who are blessed by my Father, inherit the kingdom prepared for you from the foundation of the world&rdquo; (Matt 25:34).</p>",
    "14": "<p>A direct revelation (the summary verdict): &ldquo;Therefore Hebron became the inheritance of Caleb son of Jephunneh the Kenizzite to this day, because he wholly followed YHWH, the God of Israel.&rdquo; The reason-formula is the theological summary of Caleb&rsquo;s entire narrative: Hebron is his because he wholly followed. The OT <em>milei acharei</em> theology of Caleb finds its NT fulfillment in the pattern of discipleship-as-inheritance: &ldquo;If anyone would come after me, let him deny himself and take up his cross and follow me&rdquo; (Matt 16:24). The disciples who follow wholly — even to the cross — receive the inheritance of those who did not turn back. The Kenizzite who wholly follows YHWH receives Abraham&rsquo;s city; the disciples who wholly follow Christ receive the kingdom prepared from the foundation of the world.</p>",
    "15": "<p>A type: Hebron was formerly called Kiriath-arba — after Arba, who was the greatest man among the Anakim — and the land had rest from war. The renaming of Kiriath-arba (&ldquo;city of Arba&rdquo; or &ldquo;city of four&rdquo;) to Hebron (&ldquo;alliance/community&rdquo;) at the chapter&rsquo;s close is the final typological note: the city of the greatest giant-king becomes the city of Israel&rsquo;s covenant community through the faithful man&rsquo;s inheritance claim. The name Arba (&ldquo;four&rdquo;) may connect to the four fathers buried at Hebron (Adam, Abraham, Isaac, Jacob — per later rabbinic tradition; Gen 23:2 gives Hebron/Kiriath-arba as the burial site of Sarah). The chapter ends with the note that &ldquo;the land had rest from war&rdquo; (<em>vatishkot ha'aretz milchamah</em>) — the rest-formula that echoes through the book of Joshua (11:23; 21:44) and points to the eschatological Sabbath-rest that remains for the people of God (Heb 4:9).</p>"
  }
}

def main():
    c = load_comm('mkt-christ', 'joshua')
    merge_comm(c, CHRIST)
    save_comm('mkt-christ', 'joshua', c)
    print('joshua ch 12-14: christ written')

if __name__ == '__main__':
    main()
